using System;
using System.Data.SqlClient;
using Microsoft.Extensions.Configuration;

public class DatabaseConnectionHelper : IDisposable
{
    private readonly string _connectionString;
    private SqlConnection _connection;

    /// <summary>
    /// Creates a new DatabaseConnectionHelper that reads the connection string
    /// from environment variables or user secrets — never hardcoded.
    /// 
    /// Set the environment variable before running:
    ///   Windows:  set HACKATHONDB_CONNECTION_STRING=Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;
    ///   Linux:    export HACKATHONDB_CONNECTION_STRING="Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;"
    /// 
    /// Or use .NET User Secrets (recommended for local dev):
    ///   dotnet user-secrets set "ConnectionStrings:HackathonDB" "Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;"
    /// </summary>
    public DatabaseConnectionHelper(IConfiguration configuration = null)
    {
        if (configuration != null)
        {
            _connectionString = configuration.GetConnectionString("HackathonDB");
        }

        if (string.IsNullOrWhiteSpace(_connectionString))
        {
            _connectionString = Environment.GetEnvironmentVariable("HACKATHONDB_CONNECTION_STRING");
        }

        if (string.IsNullOrWhiteSpace(_connectionString))
        {
            throw new InvalidOperationException(
                "Database connection string not found. " +
                "Set the environment variable 'HACKATHONDB_CONNECTION_STRING' or " +
                "configure 'ConnectionStrings:HackathonDB' via User Secrets or appsettings.json.");
        }
    }

    public SqlConnection GetConnection()
    {
        if (_connection == null || _connection.State == System.Data.ConnectionState.Closed)
        {
            _connection = new SqlConnection(_connectionString);
        }

        return _connection;
    }

    public SqlConnection OpenConnection()
    {
        var connection = GetConnection();
        if (connection.State != System.Data.ConnectionState.Open)
        {
            connection.Open();
        }
        return connection;
    }

    public bool TestConnection()
    {
        try
        {
            using var testConnection = new SqlConnection(_connectionString);
            testConnection.Open();
            using var command = testConnection.CreateCommand();
            command.CommandText = "SELECT 1";
            command.ExecuteScalar();
            // Do NOT log the connection string — it contains credentials
            Console.WriteLine("Database connection test succeeded.");
            return true;
        }
        catch (SqlException ex)
        {
            // Log only the error message, never the connection string
            Console.WriteLine($"Database connection test failed: {ex.Message}");
            return false;
        }
    }

    public T ExecuteScalar<T>(string query, params SqlParameter[] parameters)
    {
        using var connection = new SqlConnection(_connectionString);
        connection.Open();
        using var command = new SqlCommand(query, connection);
        if (parameters != null)
        {
            command.Parameters.AddRange(parameters);
        }
        var result = command.ExecuteScalar();
        return result == DBNull.Value ? default : (T)Convert.ChangeType(result, typeof(T));
    }

    public int ExecuteNonQuery(string query, params SqlParameter[] parameters)
    {
        using var connection = new SqlConnection(_connectionString);
        connection.Open();
        using var command = new SqlCommand(query, connection);
        if (parameters != null)
        {
            command.Parameters.AddRange(parameters);
        }
        return command.ExecuteNonQuery();
    }

    public SqlDataReader ExecuteReader(string query, params SqlParameter[] parameters)
    {
        var connection = new SqlConnection(_connectionString);
        connection.Open();
        var command = new SqlCommand(query, connection);
        if (parameters != null)
        {
            command.Parameters.AddRange(parameters);
        }
        // CommandBehavior.CloseConnection ensures the connection closes when the reader is closed
        return command.ExecuteReader(System.Data.CommandBehavior.CloseConnection);
    }

    public void Dispose()
    {
        if (_connection != null)
        {
            if (_connection.State == System.Data.ConnectionState.Open)
            {
                _connection.Close();
            }
            _connection.Dispose();
            _connection = null;
        }
